// src/components/HomeTopBar.js
import React, { useEffect, useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';

const HomeTopBar = ({ taskName }) => {
    const [user, setUser] = useState(null);
    const navigate = useNavigate();
    const location = useLocation();
    const isAnnotationPage = ['/detection', '/segmentation'].includes(location.pathname);

    useEffect(() => {
        // Get user from localStorage on component mount
        const storedUser = localStorage.getItem('user');
        if (storedUser) {
            setUser(JSON.parse(storedUser));
        } else {
            navigate('/signin');
        }
    }, [navigate]);

    const handleSignOut = () => {
        localStorage.removeItem('user');
        setUser(null);
        navigate('/signin');
    };

    return (
        <div className="bg-white shadow">
            <div className="max-w-7xl mx-auto px-4">
                <div className="flex justify-between h-16">
                    <div className="flex items-center">
                        <Link to="/" className="flex-shrink-0">
                            <h1 className="text-xl font-bold">Annotation Platform</h1>
                        </Link>

                        {!isAnnotationPage && (
                            <div className="hidden md:flex md:ml-10">
                                <Link to="/product" className="px-3 py-2 text-gray-600 hover:text-gray-900">
                                    Product
                                </Link>
                                <Link to="/pricing" className="px-3 py-2 text-gray-600 hover:text-gray-900">
                                    Pricing
                                </Link>
                                <Link to="/resources" className="px-3 py-2 text-gray-600 hover:text-gray-900">
                                    Resources
                                </Link>
                                <Link to="/company" className="px-3 py-2 text-gray-600 hover:text-gray-900">
                                    Company
                                </Link>
                            </div>
                        )}

                        {isAnnotationPage && taskName && (
                            <div className="ml-10">
                                <span className="text-gray-600">{taskName}</span>
                            </div>
                        )}
                    </div>

                    <div className="flex items-center">
                        {user && (
                            <>
                                <Link
                                    to="/tasks"
                                    className="px-3 py-2 text-gray-600 hover:text-gray-900"
                                >
                                    My Tasks
                                </Link>
                                <span className="mx-2 text-gray-400">|</span>
                                <span className="mr-4 text-gray-600">{user.username}</span>
                                <button
                                    onClick={handleSignOut}
                                    className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
                                >
                                    Sign Out
                                </button>
                            </>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default HomeTopBar;
